import React from 'react';
import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { withStyles } from '@material-ui/core/styles';
import Grid from '@material-ui/core/Grid';
import Typography from '@material-ui/core/Typography';
import Box from '@material-ui/core/Box';
import FooterImg from '../../images/footerImg.png';

const styles = {
  root: {
    backgroundColor: 'black',
    backgroundImage: `url(${FooterImg})`,
    backgroundSize: 'cover',
    backgroundPosition: 'center',
    position: 'relative',
    width: '100%',
    marginTop: '20px', // Flytta footern neråt för att undvika överlappning
  },
  h: {
    color: 'white',
    textAlign: 'center', // Centrera texten horisontellt
  },
  link: {
    color: '#FFF',
    textDecoration: 'none',
  },
};

function Footer({ classes }) {
  const { t } = useTranslation();
  return (
    <footer className={classes.root}>
      <Grid container justifyContent="space-between" alignItems="center">
        <Grid item>
          <Typography variant="h6" className={classes.h}>
            {t('welcome_message')}
          </Typography>
        </Grid>
        <Grid item>
          <Typography variant="body2">
            &copy;{new Date().getFullYear()} <Link to="https://www.limestoneweb.se" className={classes.link}>
              LIMESTONEWEB.SE
            </Link> | All rights reserved | Terms Of Service | Privacy |
          </Typography>
        </Grid>
      </Grid>
    </footer>
  );
}

export default withStyles(styles)(Footer);
